import { useEffect, useRef, useState } from 'react';
import styles from './index.module.less';
import PageBg from '../components/page-bg/page-bg';
import _ from 'lodash';
import imga from '../images/icon01.png';
import imgaa from '../images/icon01a.png';
import icon02 from '../images/icon02.png';

function App(props) {
  const [status, setStatus] = useState('');
  useEffect(() => {
    setStatus(_.get(props, 'searchParams.status'));
  }, []);
  if (!status) return null;
  return (
    <PageBg ash={status === 'fail'} className={styles['page-ract-status']}>
      <div className={`flex ${styles['top-info']} ${status === 'fail' ? styles['fail'] : ''}`}>
        <img src={status === 'fail' ?imgaa : imga} className={styles['icon01']} />
        <div className={styles['text-a']}>{status === 'fail' ? '很遗憾，通关失败' : '恭喜通关'}</div>
        <div className={styles['text-b']}>更新于：2026/04/13/19:00</div>
        <div className={styles['text-c']}>您的正确率为<span>90%</span></div>
      </div>
      <div className={`flex ${styles['count-info']}`}>
        <div className={styles['ci-tab']}><div className={styles['ci-num']}>10/10</div><div>答题数</div></div>
        <div className={styles['ci-tab']}><div className={styles['ci-num']}>02:30</div><div>用时</div></div>
      </div>
      <div className={`flex ${styles['bot-info']}`}>
        {status === 'pass' ? (
          <>
            <img src={icon02} className={styles['icon02']} />
            <div className={styles['text-d']}>多重奖励已开启</div>
            <div className={styles['text-f']}>恭喜您！完成初赛后即可获得抽奖机会<br/>同事进阶赛挑战通道也已为你同步解锁</div>
            <div className={`${styles['nm-btn']} ${styles['a']}`}>前往通关抽奖</div>
            <div className={`${styles['nm-btn']} ${styles['green']}`}>立即前往进阶赛</div>
          </>
        ) : (
          <>
            <div className={`${styles['nm-btn']} ${styles['a']}`}>重新答题</div>
            <div className={`${styles['nm-btn']} ${styles['green']}`}>返回首页</div>
          </>
        )}
      </div>
    </PageBg>
  );
}

export default App;
